fn vec_loop(mut v: Vec<i32>) -> Vec<i32> {
    for element in v.iter_mut() {
        *element *= 2;
    }
    v
}

fn vec_map(v: &Vec<i32>) -> Vec<i32> {
    v.iter().map(|element| {
        element * 2
    }).collect()
}

fn main() {
    let v = vec![2, 4, 6, 8, 10];
    println!("Loop: {:?}", vec_loop(v.clone()));
    println!("Map: {:?}", vec_map(&v));
}
